import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { getProduct } from "../../features/product/productSlice";
import { Rate, Spin } from "antd";
import {
  FaBoxOpen,
  FaCheckCircle,
  FaStore,
  FaTag,
  FaTimesCircle,
} from "react-icons/fa";

// A cute little component for info items
const InfoPill = ({ icon, label, value, className = "" }) => (
  <div className={`flex items-center gap-3 p-3 bg-white rounded-xl shadow-sm ${className}`}>
    <div className="text-xl text-pink-400">{icon}</div>
    <div>
      <p className="text-xs text-slate-500">{label}</p>
      <p className="font-semibold text-slate-700">{value}</p>
    </div>
  </div>
);

const ProductDetails = () => {
  const { id } = useParams();
  const dispatch = useDispatch();
  const product = useSelector((state) => state.product.selectedProduct);

  // State for the interactive image gallery
  const [activeImage, setActiveImage] = useState("");

  useEffect(() => {
    if (id) {
      dispatch(getProduct(id));
    }
  }, [dispatch, id]);

  // Set the first image as active when the product loads
  useEffect(() => {
    if ((Array.isArray(product?.colors?.[0]?.images) ? product?.colors?.[0]?.images?.[0]?.secure_url : product?.colors?.[0]?.images?.secure_url)) {
      setActiveImage(product.colors[0].images[0].secure_url);
    }
  }, [product]);

  // Calculate average rating
  const averageRating = product?.reviews?.length
    ? product.reviews.reduce((sum, review) => sum + review.rating, 0) /
    product.reviews.length
    : 0;

  // A cute loading spinner
  if (!product) {
    return (
      <div className="flex items-center justify-center w-full h-96">
        <Spin size="large" />
      </div>
    );
  }

  const allImages = product.colors?.flatMap(color => color.images.map(img => img.secure_url)) || [];

  return (
    <div className="min-h-screen p-4 bg-pink-50/50 sm:p-8 font-sans">
      <div className="max-w-6xl mx-auto">
        <div className="grid grid-cols-1 gap-8 lg:grid-cols-5">

          {/* --- Left Column: Image Gallery --- */}
          <div className="lg:col-span-3">
            <div className="p-4 bg-white rounded-3xl shadow-lg shadow-pink-200/50">
              <img
                src={activeImage}
                alt={product.title}
                className="w-full h-[450px] object-cover rounded-2xl transition-transform duration-300"
              />
              <div className="flex gap-3 mt-4 overflow-x-auto">
                {allImages.map((imgUrl, index) => (
                  <img
                    key={index}
                    src={imgUrl}
                    alt={`thumbnail ${index + 1}`}
                    onClick={() => setActiveImage(imgUrl)}
                    className={`w-20 h-20 object-cover rounded-lg cursor-pointer transition-all duration-200 hover:scale-105 ${activeImage === imgUrl
                        ? "ring-4 ring-pink-400"
                        : "ring-2 ring-transparent"
                      }`}
                  />
                ))}
              </div>
            </div>
          </div>

          {/* --- Right Column: Product Info --- */}
          <div className="lg:col-span-2">
            <div className="flex flex-col h-full gap-5">
              {/* Title, Brand, Category */}
              <div className="p-6 bg-white rounded-2xl shadow-lg shadow-pink-200/50">
                <span className="px-3 py-1 text-sm font-semibold tracking-wide text-pink-800 uppercase bg-pink-200 rounded-full">
                  {product.brand}
                </span>
                <h1 className="mt-2 text-4xl font-bold text-slate-800">{product.title}</h1>
                <p className="mt-1 text-slate-500">{product.category} {product.subcategory && `> ${product.subcategory}`}</p>
                <div className="flex items-center gap-2 mt-3">
                  <Rate disabled allowHalf value={averageRating} style={{ color: '#f472b6' }} />
                  <span className="font-semibold text-slate-600">{averageRating.toFixed(1)}</span>
                  <span className="text-sm text-slate-400">({product.reviews?.length || 0} reviews)</span>
                </div>
              </div>

              {/* Price */}
              <div className="p-6 bg-white rounded-2xl shadow-lg shadow-pink-200/50">
                <p className="text-lg text-slate-500">Price</p>
                <div className="flex items-baseline gap-3">
                  <span className="text-5xl font-extrabold text-pink-500">ETB{product.price}</span>
                  {product.oldPrice && (
                    <span className="text-2xl text-gray-400 line-through">ETB{product.oldPrice}</span>
                  )}
                </div>
                {product.oldPrice && (
                  <div className="px-2 py-1 mt-2 text-sm font-bold text-red-600 bg-red-100 rounded-md inline-block">
                    {Math.round(((product.oldPrice - product.price) / product.oldPrice) * 100)}% OFF
                  </div>
                )}
              </div>

              {/* Info Pills */}
              <div className="grid grid-cols-2 gap-4">
                <InfoPill icon={<FaBoxOpen />} label="Quantity" value={product.quantity} />
                <InfoPill icon={product.status === 'available' ? <FaCheckCircle /> : <FaTimesCircle />} label="Availability" value={product.status === 'available' ? 'In Stock' : 'Out of Stock'} className={product.status === 'available' ? 'text-green-500' : 'text-red-500'} />
                <InfoPill icon={<FaStore />} label="Store" value={product.store?.storeName || 'N/A'} />
                <InfoPill icon={<FaTag />} label="Tags" value={product.tags?.length || 0} />
              </div>
            </div>
          </div>
        </div>

        {/* --- Full Width Sections Below --- */}
        <div className="mt-10 space-y-8">
          {/* Description */}
          {product.description && (
            <div className="p-8 bg-white rounded-2xl shadow-lg shadow-pink-200/50">
              <h3 className="text-2xl font-bold text-slate-700 mb-4">Description</h3>
              <div
                className="prose prose-pink max-w-none"
                dangerouslySetInnerHTML={{ __html: product.description }}
              />
            </div>
          )}

          {/* Reviews */}
          <div className="p-8 bg-white rounded-2xl shadow-lg shadow-pink-200/50">
            <h3 className="text-2xl font-bold text-slate-700 mb-6">Customer Reviews</h3>
            {product.reviews?.length > 0 ? (
              <div className="space-y-6">
                {product.reviews.map((review, index) => (
                  <div key={index} className="flex gap-4 p-4 border-b border-slate-100 last:border-b-0">
                    <img src={`https://api.dicebear.com/7.x/adventurer/svg?seed=${review.name}`} alt="avatar" className="w-12 h-12 bg-pink-100 rounded-full" />
                    <div>
                      <p className="font-bold text-slate-800">{review.name}</p>
                      <Rate disabled defaultValue={review.rating} style={{ color: '#f472b6', fontSize: 16 }} className="mt-1" />
                      <p className="mt-2 text-slate-600">{review.comment}</p>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-center text-slate-500">No reviews yet. Be the first to leave one! 💖</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;